var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"[[","JPN":"AEGIS 8 PBLIT SECURITY SEQUENCE：<color=#ffd34c>ACTIVATED</color>\\nADC FACTOR：<color=#ffd34c>CONFIRMED</color>\\nMN No. FW000P5027：<color=#ffd34c>FWH-35A Titan</color>","ENG":"[[","TWN":"[[","THA":"กระบวนการตรวจสอบประวัติเพื่อความปลอดภัย AEGIS 8 PBLIT: <color=#ffd34c>เริ่มการทำงาน</color>\\nADC แฟกเตอร์: <color=#ffd34c>ยืนยัน</color> \\nMN หมายเลข FW000P5027: <color=#ffd34c>ไททัน FWH-35A</color>","VTN":"TRÌNH TỰ AN NINH AEGIS 8 PBLIT: <color=#ffd34c>ĐÃ KÍCH HOẠT</color>\\nTHÔNG SỐ ADC: <color=#ffd34c>ĐÃ XÁC NHẬN</color>\\nMN Số FW000P5027: <color=#ffd34c>FWH-35A Titan</color>","SCN":"AEGIS 8 PBLIT 安全序列: <color=#ffd34c>激活</color>\\nADC 因素: <color=#ffd34c>确认</color>\\nMN No.FW000P5027: <color=#ffd34c>FWH-35A Titan</color>","DEU":"AEGIS 8 PBLIT-SICHERHEITSSEQUENZ: <color=#ffd34c>AKTIVIERT</color>\\nADC-FAKTOR: <color=#ffd34c>ALPHA BESTÄTIGT</color>\\nMN-Nr. FW000P5027: <color=#ffd34c>FWH-35A Titan</color>","FRA":"AEGIS 8 PROTOCOLE DE SÉCURITÉ PBLIT\xA0: <color=#ffd34c>ACTIVÉ</color>     \\nFACTEUR CAD\xA0: <color=#ffd34c>ALPHA CONFIRMÉ</color>     \\nMN No. FW000P5027\xA0: <color=#ffd34c>Titan\xA0FWH-35A</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"가장 큰 난관은 역시 하중에 의한 부하겠죠.","JPN":"最大の難関は、やはり荷重による負荷です。","ENG":"The greatest challenge has to be stress from the weight.","TWN":"最大的難關果然還是負荷問題吧。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"전체 하중은 시뮬레이션을 거쳐서 줄일 대로 줄였어요. 그런데도 예상 부하의 60% 가량을 지지하는 게 한계입니다.","JPN":"全体の荷重はシミュレーションを経て、減らせるだけ減らしました。\\nそれでも、予想負荷の60％以上を支えるのが限界です。","ENG":"We've already reduced the overall weight as much as possible during the simulations. Still, we can only support up to 60% of the estimated load.","TWN":"我們通過模擬儘量減少了總負重。但也只能維持預期負荷的60%。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_RECORD","text":{"KOREA":"젠장, 이럴 거면 기술자들은 뭐 하러 여기 앉혀 놓나?","JPN":"ちくしょう、エンジニアがここにいる意味がない！","ENG":"What's the use of all these engineers then?","TWN":"媽的，技術人員都是幹什麼吃的？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_RECORD","text":{"KOREA":"하나부터 열까지 말도 안 되는 문제만 튀어나오는데.","JPN":"こんな問題を私たちにどうしろって言うんだ！","ENG":"We keep getting these ridiculous problems.","TWN":"就不能讓我聽聽好消息嗎？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_RECORD","text":{"KOREA":"애초에 이족보행병기 같은 걸 만들자는 아이디어는 누가 내놓은 거야?","JPN":"大体、二足歩行兵器を作るなんてアイデアを出したのは誰だ！？","ENG":"Whose idea was it to make a bipedal weapon system in the first place?","TWN":"當初是誰提出要製造人形機甲的？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"누구긴 누구겠습니까. 엠버 소장님이지.","JPN":"アンバー所長に決まってるじゃないですか。","ENG":"Who else? Director Ember.","TWN":"還會是誰。當然是琥珀所長啊。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_RECORD","text":{"KOREA":"정말이지...... 그 여자는 인공지능만 꽂으면 앉은뱅이가 일어나기라도 할 줄 아는 건가?","JPN":"くそ……あの女は、人工知能さえ搭載すればロボットが立ち上がるとでも思ってるのか？","ENG":"Seriously... That woman probably thinks an A.I. could make the lame walk again.","TWN":"不會吧……那女的不會真的以為只要把人工智慧裝進去，瘸子也能站起來吧？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"EMBER_NPC_NULL_NULL","text":{"KOREA":"회의 석상에서 말씀이 너무 지나치십니다. 체르노프 교수님.","JPN":"会議中なのに言葉が過ぎますよ。チェルノフ教授。","ENG":"I'd choose my words more carefully at an official meeting if I were you. Professor Chernov.","TWN":"您正坐在會議桌上，請注意自己的發言。切爾諾夫教授。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"아, 소, 소장님! 오셨습니까?","JPN":"あ、しょ、所長！","ENG":"Oh, D-Director! I didn't know you were coming...","TWN":"啊，少，少校！您來啦？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_RECORD","text":{"KOREA":"크흠.....!","JPN":"こほん……！","ENG":"Ahem!","TWN":"咳咳……！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"EMBER_NPC_NULL_NULL","text":{"KOREA":"구동계 설계가 지지부진하대서 와 봤더니, 아니나 다를까 불평 불만만 늘어놓고 계시네요, 체르노프 교수님.","JPN":"駆動系の設計がうまくいってないという話を聞いて来てみれば……\\nやはり文句ばかり言っておられるんですね、チェルノフ教授。","ENG":"I dropped by to check on the delay with the thruster designs, and what do you know, here I find you doing nothing but complaining, Professor Chernov.","TWN":"我聽說驅動程式設計專案進度緩慢，所以就過來看看。果然您就只是在大肆抱怨呢，切爾諾夫教授。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"EMBER_NPC_NULL_NULL","text":{"KOREA":"이젠 슬슬 인정하실 때도 되지 않았나요?","JPN":"そろそろお認めになってはいかがです？","ENG":"Isn't it about time you admitted it though?","TWN":"現在差不多可以承認了吧？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_RECORD","text":{"KOREA":"뭐를? 자네의 그 정신 나간 아이디어를?","JPN":"何を認めればいいんだ？　君のその狂ったアイデアか？","ENG":"Admit what? That your idea is absolutely ridiculous?","TWN":"承認什麼？你那愚蠢的主意嗎？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_RECORD","text":{"KOREA":"아니면 관리국 놈들이 주는 엉터리 같은 데이터를?","JPN":"それとも、管理局のやつらが渡してきたでたらめのデータか？","ENG":"Or how worthless the data from the Administration is?","TWN":"還是管理局那群傢伙提供荒唐資料？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_RECORD","text":{"KOREA":"우리가 왜 퓨처 앳 워 계획에 참가했는지 알기는 아나?","JPN":"なぜ私たちが、フューチャーアットウォー計画に参加したか知ってるか？","ENG":"Do you know why we participated in the Future at War Project in the first place?","TWN":"你知道我們為什麼參加天啟兵器計畫嗎？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_RECORD","text":{"KOREA":"저 망할 전쟁 때문에 죽어 나가는 사람이 없게 하기 위해서야!","JPN":"これ以上、あのクソみたいな戦争で、死者を出したくないからだ！","ENG":"It was to make sure no more people die in that blasted war!","TWN":"是為了不讓人們因為那該死的戰爭死去！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_RECORD","text":{"KOREA":"장난감이나 만들자고 전세계 석학들이 이리로 모여든 게 아닐세!","JPN":"おもちゃを作るために、世界中の著名な学者たちが、ここに集まったわけじゃないんだ！","ENG":"We didn't put the world's greatest minds together just to build some toys!","TWN":"世界各地的頂級學者不是為了製作玩具才聚集到這裡的！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};